 14	import { TFunction } from 'react-i18next';
 15	import {
 16	  Modal,
 17	  ModalVariant,
 18	  Button,
 19	  ButtonVariant,
 20	  PaginationVariant,
 21	} from '@patternfly/react-core';
 22	import { Tr, Td, TableVariant } from '@patternfly/react-table';
 23	import { ObjectCrFormat } from '../../../types';
 24	import { replacePathFromName } from '../../../utils';
 25	import './delete-objects.scss';
 26	
 27	type DeleteObjectsSummaryProps = {
 28	  errorResponse: DeleteObjectsCommandOutput['Errors'];
 29	  selectedObjects: ObjectCrFormat[];
 30	  foldersPath: string;
 31	};
 32	
 33	type DeleteObjectsMap = { [objectName: string]: ObjectCrFormat };
 34	
 35	type SummaryRowComponent = React.ComponentType<RowComponentType<unknown>>;
 36	
 37	const getColumnNames = (t: TFunction) => [
 38	  '', // expandable
 39	  t('Name'),
 40	  t('Size'),
 41	  t('Last modified'),
 42	  t('Delete status'),
 43	];
 44	
 45	const getHeaderColumns = (t: TFunction) => {
 46	  const columnNames = getColumnNames(t);
 47	  return [
 48	    {
 49	      columnName: columnNames[0],
 50	    },
 51	    {
 52	      columnName: columnNames[1],
 53	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
 54	    },
 55	    {
 56	      columnName: columnNames[2],
 57	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.size'),
 58	    },
 59	    {
 60	      columnName: columnNames[3],
 61	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.lastModified'),
 62	    },
 63	    {
 64	      columnName: columnNames[4],
 65	    },
 66	  ];
 67	};
 68	
 69	const ObjectsSummaryTableRow: React.FC<RowComponentType<_Error>> = ({
 70	  row: object,
 71	  rowIndex,
 72	  extraProps,
 73	}) => {
 74	  const { t } = useCustomTranslation();
 75	
 76	  const [isExpanded, setIsExpanded] = React.useState<boolean>(false);
 77	
 78	  const { foldersPath, deleteObjectsMap } = extraProps;
 79	  const objectName = object?.Key || DASH;
 80	  const objectCrFormat = deleteObjectsMap[objectName] || {};
 81	  const name = replacePathFromName(objectName, foldersPath);
 82	
 83	  const columnNames = getColumnNames(t);
 84	
 85	  return (
 86	    <>
 87	      <Tr>
 88	        <Td
 89	          data-test="expand-button"
 90	          expand={{
 91	            rowIndex,
 92	            isExpanded: isExpanded,
 93	            onToggle: () => setIsExpanded(!isExpanded),
 94	            expandId: 'expandable-table',
 95	          }}
 96	        />
 97	        <Td dataLabel={columnNames[1]}>{name}</Td>
 98	        <Td dataLabel={columnNames[2]}>
 99	          {objectCrFormat.apiResponse?.size || DASH}
100	        </Td>
101	        <Td dataLabel={columnNames[3]}>
102	          {objectCrFormat.apiResponse?.lastModified || DASH}
103	        </Td>
104	        <Td dataLabel={columnNames[4]}>
105	          <RedExclamationCircleIcon className="pf-v6-u-mr-sm" />
106	          {t('Failed')}
107	        </Td>
108	      </Tr>
109	      {isExpanded && (
110	        <Tr>
111	          <Td colSpan={Object.keys(columnNames).length + 1}>
112	            <RedExclamationTriangleIcon className="pf-v6-u-mr-sm" />
113	            {object?.Message || DASH}
114	          </Td>
115	        </Tr>
116	      )}
117	    </>
118	  );
119	};
120	
121	const DeleteObjectsSummary: React.FC<
122	  CommonModalProps<DeleteObjectsSummaryProps>
123	> = ({
124	  closeModal,
125	  isOpen,
126	  extraProps: { errorResponse, selectedObjects, foldersPath },
127	}) => {
128	  const { t } = useCustomTranslation();
129	
130	  const deleteObjectsMap: DeleteObjectsMap = React.useMemo(
131	    () =>
132	      selectedObjects.reduce((acc, object) => {
133	        acc[getName(object)] = object;
134	        return acc;
135	      }, {} as DeleteObjectsMap),
136	    [selectedObjects]
137	  );
138	
139	  return (
140	    <Modal
141	      title={t('Object delete summary')}
142	      isOpen={isOpen}
143	      onClose={closeModal}
144	      variant={ModalVariant.default}
145	      actions={[
146	        <Button variant={ButtonVariant.primary} onClick={closeModal}>
147	          {t('Close')}
148	        </Button>,
149	      ]}
150	    >
151	      <div className="objects-table">
152	        <PaginatedListPage
153	          filteredData={errorResponse}
154	          hideFilter
155	          composableTableProps={{
156	            columns: getHeaderColumns(t),
157	            RowComponent: ObjectsSummaryTableRow as SummaryRowComponent,
158	            extraProps: { foldersPath, deleteObjectsMap },
159	            unfilteredData: errorResponse as [],
160	            loaded: true,
161	            variant: TableVariant.compact,
162	          }}
163	          paginationProps={{
164	            variant: PaginationVariant.top,
165	            dropDirection: 'down',
166	            perPageOptions: [{ title: '10', value: 10 }],
167	          }}
168	        />
169	      </div>
170	    </Modal>
171	  );
172	};
173	
174	export default DeleteObjectsSummary;

